// Extract event data from router payload
const input = $input.first().json;

// Router sends: { event_id, event_type, project_id, payload }
const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

const protocolId = payload.protocol_id;

// Step key is protocol-specific
const stepKey = `inspection_finalize:${protocolId}`;

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    protocol_id: protocolId,
    step_key: stepKey
  }
};

// Collect protocol info and deviations to build summary
const protocol = $('Load Protocol + Project').first().json;
const deviationItems = $('Load Deviations').all().map(i => i.json);
const eventData = $('Parse Event Data').first().json;

// Count total positions for this protocol
// Deviations are the items with issues; we also need total count
const deviations = deviationItems.filter(d => d.deviation_type && !d.is_additional);
const additional = deviationItems.filter(d => d.is_additional);

const deviationCount = deviations.length;
const additionalCount = additional.length;

// Build deviations JSON for request_data
const deviationsJson = deviationItems.map(d => ({
  id: d.id,
  deviation_type: d.deviation_type,
  is_additional: d.is_additional,
  position_title: d.position_title,
  position_number: d.position_number,
  room_name: d.room_name,
  notes: d.notes,
  catalog_position_nr: d.catalog_position_nr
}));

const summaryText = `\u2705 bestätigt, \u26A0\uFE0F ${deviationCount} Abweichungen, \u2795 ${additionalCount} Zusatzleistungen`;

return {
  json: {
    event_id: eventData.event_id,
    project_id: eventData.project_id,
    protocol_id: eventData.protocol_id,
    step_key: eventData.step_key,
    protocol_type: protocol.protocol_type,
    inspection_date: protocol.inspection_date,
    finalized_at: protocol.finalized_at,
    finalized_by: protocol.finalized_by,
    finalized_by_name: protocol.finalized_by_name || 'Unbekannt',
    project_number: protocol.project_number,
    project_name: protocol.project_name,
    object_street: protocol.object_street,
    deviation_count: deviationCount,
    additional_count: additionalCount,
    summary_text: summaryText,
    deviations_json: JSON.stringify(deviationsJson)
  }
};

// Capture approval_id and merge with earlier data
const approval = $input.first().json;
const summary = $('Build Summary').first().json;

return {
  json: {
    ...summary,
    approval_id: approval.id
  }
};

